// ─── TAX HELPERS ──────────────────────────────────────────────────
const rMap={irpf_cat1:["IRPF I",C.purple],irpf_cat2:["IRPF II","#4F46E5"],irae:["IRAE",C.navy]};
const vMap={basica:["IVA 22%",C.blue],reducida:["IVA 10%",C.teal],minimo:["IVA Min",C.warn],sp:["IVA SP",C.teal],monotributo:["MONO",C.ok]};
function taxTags(taxes){
  if(!taxes)return[];
  const t=[];
  if(rMap[taxes.renta])t.push(rMap[taxes.renta]);
  if(vMap[taxes.iva])  t.push(vMap[taxes.iva]);
  if(taxes.patrimonio) t.push(["IP",C.red]);
  return t;
}
function isConf(c){const t=c.taxes;return t&&(t.renta!=="ninguno"||t.iva!=="no_aplica"||t.patrimonio);}

// ─── RULES ENGINE ─────────────────────────────────────────────────
function getObs(client){
  const t=client.taxes||{};
  const obs=[];
  const M=(o)=>obs.push({freq:"mensual", paid:false,notified:false,...o});
  const A=(o)=>obs.push({freq:"anual",   paid:false,notified:false,...o});
  const E=(o)=>obs.push({freq:"especial",paid:false,notified:false,...o});
  if(t.renta==="irpf_cat1"){M({id:"irpf1",label:"Control retenciones IRPF Cat I",org:"DGI",url:"dgi"});A({id:"dj_irpf1",label:"DDJJ IRPF anual – Form. 1102 (Cat I)",org:"DGI",form:"1102",url:"dgi"});}
  if(t.renta==="irpf_cat2"){M({id:"irpf2",label:"Anticipo IRPF Cat II",org:"DGI",url:"dgi"});M({id:"bps_ind",label:"Aportes BPS titular/independiente",org:"BPS",url:"bps"});A({id:"dj_irpf2",label:"DDJJ IRPF anual – Form. 1102 (Cat II)",org:"DGI",form:"1102",url:"dgi"});}
  if(t.renta==="irae"){M({id:"irae_ant",label:"Anticipo mensual IRAE",org:"DGI",url:"dgi",autoCalc:true,hint:"~$6.550/mes"});M({id:"bps_soc",label:"Aportes BPS socios/directores",org:"BPS",url:"bps"});A({id:"dj_irae",label:"DDJJ IRAE anual (25% renta neta)",org:"DGI",url:"dgi"});}
  if(t.patrimonio&&t.renta!=="ninguno")A({id:"dj_ip",label:"DDJJ Impuesto al Patrimonio / IP (1,5%)",org:"DGI",url:"dgi"});
  if(t.iva==="basica")M({id:"dj_iva",label:"DJ IVA mensual – Form. 2178 (22%)",org:"DGI",form:"2178",url:"dgi"});
  if(t.iva==="reducida")M({id:"dj_iva_r",label:"DJ IVA mensual – Form. 2178 (10%)",org:"DGI",form:"2178",url:"dgi"});
  if(t.iva==="minimo"){M({id:"dj_min",label:"Pago IVA Mínimo – Boleto 2908",org:"DGI",form:"2908",url:"dgi",autoCalc:true});M({id:"bps_lit",label:"Aportes BPS titular (Literal E)",org:"BPS",url:"bps"});}
  if(t.iva==="sp")M({id:"dj_1302",label:"DJ IVA Serv. Personales – Form. 1302",org:"DGI",form:"1302",url:"dgi"});
  if(t.iva==="monotributo")M({id:"mt",label:"Cuota Monotributo unificada (BPS+DGI)",org:"BPS/DGI",url:"bps",autoCalc:true});
  if(client.entityType==="sas")M({id:"fonasa_sas",label:"FONASA directores SAS (mín. 15 BFC)",org:"BPS",url:"bps"});
  if(["sa","sas"].includes(client.entityType))A({id:"bcu",label:"Beneficiarios finales BCU (Ley 19.484)",org:"BCU"});
  if(client.nature==="construccion"){M({id:"focer",label:"FOCER – Cesantía Construcción",org:"BPS",url:"bps"});M({id:"fsc",label:"Fondo Social Construcción",org:"BPS",url:"bps"});M({id:"fosvoc",label:"FOSVOC – Vivienda Obrera",org:"BPS",url:"bps"});}
  if(client.specialTaxes?.includes("gasoil"))A({id:"gasoil",label:"DJ Gasoil – Form. 2181",org:"DGI",form:"2181",url:"dgi"});
  if(client.hasEmployees){
    M({id:"bps_nom",label:"Declaración nominada nómina (BPS)",org:"BPS",url:"bps",needsNominas:true});
    M({id:"irpf_dep",label:"Retención IRPF dependientes (código 104)",org:"BPS/DGI",url:"bps"});
    A({id:"bse_seg",label:"Seguro accidentes laborales (BSE)",org:"BSE",url:"bse"});
    E({id:"aguin_jun",label:"Aguinaldo – 1ª cuota (junio)",org:"DGI/BPS"});
    E({id:"aguin_dic",label:"Aguinaldo – 2ª cuota (diciembre)",org:"DGI/BPS"});
    E({id:"aj_dic",label:"Ajuste anual IRPF dependientes (dic.)",org:"DGI/BPS"});
  }
  if(t.iva!=="monotributo"&&isConf(client))M({id:"efact",label:"Control e-Factura CFE",org:"DGI",url:"dgi"});
  return obs;
}

